import React, { useState } from "react";
import "./PathologyPage.css";

const PathologyPage = () => {
  const [selectedTest, setSelectedTest] = useState(null);

  const healthCheckups = [
    { name: "STD Checkups", img: "https://cdn-icons-png.flaticon.com/512/4140/4140048.png" },
    { name: "Fever Checkups", img: "https://cdn-icons-png.flaticon.com/512/3075/3075977.png" },
    { name: "PCOD Checkups", img: "https://cdn-icons-png.flaticon.com/512/3004/3004613.png" },
    { name: "Senior Citizen", img: "https://cdn-icons-png.flaticon.com/512/3048/3048122.png" },
  ];

  const healthTests = [
    { name: "Kidney Function Test", img: "https://cdn-icons-png.flaticon.com/512/616/616408.png" },
    { name: "Vitamin D, 25-Hydroxy", img: "https://cdn-icons-png.flaticon.com/512/2750/2750686.png" },
    { name: "HbA1c", img: "https://cdn-icons-png.flaticon.com/512/2170/2170153.png" },
    { name: "Lipid Profile", img: "https://cdn-icons-png.flaticon.com/512/684/684908.png" },
  ];

  const bodyCheckups = [
    { name: "Full Body Checkup - Essential", price: "₹1599", offer: "70% Off" },
    { name: "Full Body Checkup - Advanced", price: "₹2699", offer: "68% Off" },
    { name: "Ultra Full Body Checkup - Male", price: "₹11999", offer: "66% Off" },
  ];

  const handleClick = (item) => setSelectedTest(item);
  const closePopup = () => setSelectedTest(null);

  return (
    <div className="pathology-container">
      <h2>Popular Health Checkups</h2>
      <div className="grid-section">
        {healthCheckups.map((item, index) => (
          <div key={index} className="card" onClick={() => handleClick(item)}>
            <img src={item.img} alt={item.name} />
            <p>{item.name}</p>
          </div>
        ))}
      </div>

      <h2>Popular Health Tests</h2>
      <div className="grid-section">
        {healthTests.map((item, index) => (
          <div key={index} className="card" onClick={() => handleClick(item)}>
            <img src={item.img} alt={item.name} />
            <p>{item.name}</p>
          </div>
        ))}
      </div>

      <h2>Full Body Checkups</h2>
      <div className="body-checkup-section">
        {bodyCheckups.map((item, index) => (
          <div key={index} className="body-card" onClick={() => handleClick(item)}>
            <h4>{item.name}</h4>
            <p className="price">{item.price}</p>
            <p className="offer">{item.offer}</p>
            <div className="btns">
              <button className="view-btn">View Details</button>
              <button className="cart-btn">Add to Cart</button>
            </div>
          </div>
        ))}
      </div>

      {selectedTest && (
        <div className="popup-overlay" onClick={closePopup}>
          <div className="popup" onClick={(e) => e.stopPropagation()}>
            <h3>{selectedTest.name}</h3>
            {selectedTest.img && <img src={selectedTest.img} alt={selectedTest.name} />}
            {selectedTest.price && <p className="popup-price">{selectedTest.price}</p>}
            <p>
              {selectedTest.description ||
                "Comprehensive test to evaluate key health indicators and ensure overall well-being."}
            </p>
            <button onClick={closePopup} className="close-btn">Close</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default PathologyPage;
